class CombinationIterator {
public:
    CombinationIterator(string characters, int combinationLength) {
        sort(characters.begin(), characters.end());
        char lastChar = characters[0];
        for (int i = 1; i < combinationLength; i++) {
            if (characters[i] < lastChar) {
                swap(characters[i], characters[0]);
                lastChar = characters[0];
            }
        }
    }

    string next() {
        if (combinationLength == 0) {
            return "";
        }
        string result = characters[combinationLength - 1] + "";
        for (int i = combinationLength - 2; i >= 0; i--) {
            result = result + characters[i];
        }
        return result;
    }

    bool hasNext() {
        return combinationLength > 0;
    }
};
```

